select count(1)
from courses

  and deleted = false

    and course_name like concat('%', #{keyword}, '%')


    and category_name = #{categoryName}


    and status = #{status}

select id, course_name, category_name, hot_score, chapter_count, status, update_time, created_at, updated_at, created_by, updated_by, deleted
from courses

  and deleted = false

    and course_name like concat('%', #{keyword}, '%')


    and category_name = #{categoryName}


    and status = #{status}


order by id desc
limit #{pageSize} offset #{offset}

